import{_ as o,o as a,c,a3 as n}from"./chunks/framework.CRbjHCyB.js";const u=JSON.parse('{"title":"源码概览","description":"","frontmatter":{},"headers":[],"relativePath":"zh/clice/design/overview.md","filePath":"zh/clice/design/overview.md"}'),l={name:"zh/clice/design/overview.md"};function i(d,e,r,s,t,p){return a(),c("div",null,[...e[0]||(e[0]=[n('<h1 id="源码概览" tabindex="-1">源码概览 <a class="header-anchor" href="#源码概览" aria-label="Permalink to &quot;源码概览&quot;">​</a></h1><p>本文档介绍 clice 源码中各模块的职责与定位，帮助读者建立对整个项目结构的初步认知。关于每个模块的详细设计，请参阅对应的专题文档。</p><h2 id="项目定位" tabindex="-1">项目定位 <a class="header-anchor" href="#项目定位" aria-label="Permalink to &quot;项目定位&quot;">​</a></h2><p>clice 是一个全新的 C++ 语言服务器，从架构层面重新设计，解决以往 C++ 语言服务器中长期存在的问题。主要特点：</p><ul><li><p><strong>编译上下文</strong>：clice 是第一个将编译上下文作为正式概念引入的语言服务器。编译、索引、查询的每一步都明确区分当前使用的编译上下文，用户可以查询和切换。详见 <a href="./compilation-context">编译上下文</a>。</p></li><li><p><strong>多进程架构</strong>：通过 master + worker 的进程模型隔离 Clang 的内存泄漏和崩溃问题，同时实现优先级调度和实时内存监控。详见 <a href="./multi-process">多进程架构</a>。</p></li><li><p><strong>协程异步模型</strong>：基于 C++20 协程和 kotatsu 库，取代传统的回调式异步，使业务逻辑更清晰。</p></li><li><p><strong>实时模块编译</strong>：基于引用计数的 C++20 模块编译 DAG，支持实时取消和依赖级联。详见 <a href="./module-graph">模块编译图</a>。</p></li></ul><h2 id="模块概览" tabindex="-1">模块概览 <a class="header-anchor" href="#模块概览" aria-label="Permalink to &quot;模块概览&quot;">​</a></h2><h3 id="src-support-—-基础工具库" tabindex="-1"><code>src/support/</code> — 基础工具库 <a class="header-anchor" href="#src-support-—-基础工具库" aria-label="Permalink to &quot;`src/support/` — 基础工具库&quot;">​</a></h3><p>通用工具和基础设施，被其他所有模块共享。</p><ul><li><code>PathPool</code>：将文件路径内部化为 <code>uint32_t</code> 标识符，在整个系统中用作文件的稳定标识</li><li><code>FuzzyMatcher</code>：分词感知的模糊匹配，用于代码补全和符号搜索</li><li>Markup / Doxygen：文档注释的解析与格式化</li><li>日志、文件系统抽象、字符串工具等</li></ul><h3 id="src-command-—-编译命令处理" tabindex="-1"><code>src/command/</code> — 编译命令处理 <a class="header-anchor" href="#src-command-—-编译命令处理" aria-label="Permalink to &quot;`src/command/` — 编译命令处理&quot;">​</a></h3><p>从编译数据库（CDB）读取的命令是构建系统生成的原始命令，不能直接交给 Clang 前端使用——可能包含仅用于代码生成的选项、缺少系统头文件搜索路径、或包含语言服务器不需要的参数。这个模块负责对原始命令进行分类、过滤、工具链探测和去重，转化为语言服务器可消费的编译参数。</p><ul><li><code>CompilationDatabase</code>：加载 <code>compile_commands.json</code>，将编译命令分为影响语义的标志（canonical）和仅影响用户内容的标志（patch，如 <code>-I</code>、<code>-D</code>），实现跨文件的命令去重与共享</li><li><code>Toolchain</code>：通过系统编译器查询完整的编译参数（如系统头文件搜索路径），按 (driver, file extension, non-user-content flags) 缓存查询结果</li><li><code>SearchConfig</code>：头文件搜索路径的四段式模型（Quoted / Angled / System / After），与 Clang 内部的搜索逻辑一致</li></ul><p>详见 <a href="./command-resolve">编译命令解析</a>。</p><h3 id="src-compile-—-编译抽象" tabindex="-1"><code>src/compile/</code> — 编译抽象 <a class="header-anchor" href="#src-compile-—-编译抽象" aria-label="Permalink to &quot;`src/compile/` — 编译抽象&quot;">​</a></h3><p>对 Clang 编译器的封装，将 Clang API 抽象为安全、统一的编译接口。这一层是纯粹的编译抽象，不涉及任何服务器逻辑。</p><ul><li><code>CompilationUnit</code> / <code>CompilationUnitRef</code>：对 Clang AST 上下文的 RAII 封装。<code>CompilationUnitRef</code> 提供统一的只读视图，用于访问源码位置映射、预处理指令、AST 节点等，是 <code>src/feature/</code> 和 <code>src/semantic/</code> 的主要输入</li><li><code>CompilationParams</code>：描述一次编译的完整配置，包括编译类型（Preamble / Content / Completion / Indexing 等）、文件重映射、PCH/PCM 复用等</li></ul><h3 id="src-syntax-—-轻量级语法处理" tabindex="-1"><code>src/syntax/</code> — 轻量级语法处理 <a class="header-anchor" href="#src-syntax-—-轻量级语法处理" aria-label="Permalink to &quot;`src/syntax/` — 轻量级语法处理&quot;">​</a></h3><p>不依赖完整 AST 的语法层处理，运行在编译之前，用于快速获取文件的结构信息和依赖关系。</p><ul><li><code>Lexer</code>：基于 Clang raw lexer 的 token 级别工具，不经过预处理器，用于指令扫描、include 路径解析等</li><li><code>DependencyGraph</code>：全局的 include / module 依赖关系图，支持正向查询、反向查询、宿主源文件搜索、include 链查找等</li><li>依赖扫描：封装 Clang 的 <code>DependencyDirectivesScanner</code>，快速提取 include 和 module 依赖</li><li><code>IncludeResolver</code>：根据搜索路径配置解析 include 路径到实际文件</li></ul><p>详见 <a href="./dependency-scanning">依赖扫描</a>。</p><h3 id="src-semantic-—-语义分析" tabindex="-1"><code>src/semantic/</code> — 语义分析 <a class="header-anchor" href="#src-semantic-—-语义分析" aria-label="Permalink to &quot;`src/semantic/` — 语义分析&quot;">​</a></h3><p>超越 Clang 原生 API 的语义分析能力。接收 <code>CompilationUnitRef</code>，提取更高层次的语义信息。</p><ul><li><code>SemanticVisitor</code>：AST 遍历器，记录每个符号的出现位置和关系（定义、引用、继承、调用等），是索引数据的主要生产者</li><li><code>TemplateResolver</code>：通过伪实例化技术解析依赖名称（dependent names），使语义分析能穿透模板上下文。详见 <a href="./template-resolver">模板解析器</a></li><li><code>SymbolKind</code> / <code>RelationKind</code>：细粒度的符号种类和关系类型</li></ul><h3 id="src-index-—-符号索引" tabindex="-1"><code>src/index/</code> — 符号索引 <a class="header-anchor" href="#src-index-—-符号索引" aria-label="Permalink to &quot;`src/index/` — 符号索引&quot;">​</a></h3><p>符号索引系统，支持跨翻译单元的查询。采用三级结构：</p><ul><li><code>TUIndex</code>：单次编译产出的索引数据，由 <code>SemanticVisitor</code> 生成</li><li><code>ProjectIndex</code>：全局符号表，汇聚所有已索引文件的符号信息，支持按符号哈希查询</li><li><code>MergedIndex</code>：按文件分片的索引存储，将同一文件在不同编译上下文下产生的索引数据合并</li></ul><p>详见 <a href="./symbol-index">符号索引</a>。</p><h3 id="src-feature-—-lsp-功能实现" tabindex="-1"><code>src/feature/</code> — LSP 功能实现 <a class="header-anchor" href="#src-feature-—-lsp-功能实现" aria-label="Permalink to &quot;`src/feature/` — LSP 功能实现&quot;">​</a></h3><p>LSP 功能的具体实现。每个功能接收一个 <code>CompilationUnitRef</code>，返回对应的 LSP 响应数据。这一层是纯粹的计算层，不涉及网络通信、状态管理或进程调度。</p><p>包括：代码补全、悬停信息、签名帮助、语义高亮、内嵌提示、文档符号、文档链接、折叠范围、格式化、诊断等。</p><blockquote><p><code>feature/</code> 只涵盖单文件、基于 AST 的特性实现。跨文件的导航功能（go to definition、find references 等）由 <code>Indexer</code> 基于索引数据完成。部分功能存在多阶段处理——例如代码补全中的 include 路径补全在语法层就能完成，不需要完整编译。</p></blockquote><h3 id="src-server-—-服务器运行时" tabindex="-1"><code>src/server/</code> — 服务器运行时 <a class="header-anchor" href="#src-server-—-服务器运行时" aria-label="Permalink to &quot;`src/server/` — 服务器运行时&quot;">​</a></h3><p>语言服务器的核心运行时，负责将上述所有层组装成一个可运行的服务。</p><p><strong><code>protocol/</code></strong> — 协议定义。描述主进程与工作进程之间、以及与客户端之间的通信消息格式。包括 Worker 协议（编译/查询/构建请求）、LSP 扩展协议（编译上下文切换等）、以及面向 AI agent 的 agentic 协议。</p><p><strong><code>workspace/</code></strong> — 项目级全局状态。<code>Workspace</code> 持有编译数据库、工具链、路径池、依赖图、PCH/PCM 缓存、项目索引等全部项目级状态。核心不变量：打开文件的未保存缓冲区内容不会修改 <code>Workspace</code>，它只反映磁盘上的状态。</p><p><strong><code>compiler/</code></strong> — 编译调度与索引管理。</p><ul><li><code>Compiler</code>：编译生命周期的调度器，协调 PCH 构建、模块依赖解析、AST 编译的先后顺序，将编译任务分发给工作进程</li><li><code>CompileGraph</code>：C++20 模块编译的 DAG 调度器，基于引用计数实现兴趣追踪，支持依赖级联取消</li><li><code>Indexer</code>：后台索引调度和跨文件查询的入口，综合 <code>ProjectIndex</code>、<code>MergedIndex</code> 和打开文件的内存索引提供查询结果</li></ul><p><strong><code>service/</code></strong> — 服务入口与会话管理。</p><ul><li><code>MasterServer</code>：顶层协调器，持有 <code>Workspace</code>、<code>Session</code> 映射、<code>WorkerPool</code>、<code>Compiler</code>、<code>Indexer</code>，将 LSP 请求路由到对应的处理逻辑</li><li><code>Session</code>：每个打开文件的编辑状态（缓冲区内容、编译版本号、内存索引、PCH 引用等），在 didOpen 时创建，didClose 时销毁</li><li><code>LSPClient</code> / <code>AgentClient</code>：LSP 协议和 agentic 协议的请求处理器</li></ul><p><strong><code>worker/</code></strong> — 工作进程管理。</p><ul><li><code>WorkerPool</code>：管理工作进程的生命周期和调度。有状态工作进程（<code>StatefulWorker</code>）持有 AST 服务查询请求，无状态工作进程（<code>StatelessWorker</code>）执行一次性任务（PCH/PCM 构建、补全、索引等）</li><li>进程容错：工作进程崩溃时自动重启，有状态工作进程崩溃时自动重新分配文档</li></ul><p>详见 <a href="./multi-process">多进程架构</a>。</p><h2 id="模块间关系" tabindex="-1">模块间关系 <a class="header-anchor" href="#模块间关系" aria-label="Permalink to &quot;模块间关系&quot;">​</a></h2><p>数据流方向大致为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>command（编译命令解析）</span></span>\n<span class="line"><span>    ↓</span></span>\n<span class="line"><span>compile（驱动 Clang 编译）</span></span>\n<span class="line"><span>    ↓</span></span>\n<span class="line"><span>semantic（提取语义信息） ──→ index（构建索引）</span></span>\n<span class="line"><span>    ↓</span></span>\n<span class="line"><span>feature（产出 LSP 响应）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>server 层将以上各层通过 Workspace / Session / WorkerPool 组装成可运行的服务</span></span></code></pre></div><p><code>support</code> 和 <code>syntax</code> 是横切层，被多个模块共享。</p>',46)])])}const m=o(l,[["render",i]]);export{u as __pageData,m as default};
